        let m: number = mat[1];
        let q: number = other[0];
        let p: number = other[1];
        if (m !== q)
            throw RangeError(`Cannot multiply ${n}x${m} matrix with ${q}x${p} matrix.`);
        let res: Matrix = create(n, p);
        // Iterate through rows and columns
        for (let i = 0; i < n; ++i)
            for (let j = 0; j < p; ++j) {
                // Sum up rows from this with columns from other matrix.
                let val: number = 0;
                for (let k = 0; k < m; ++k)
                    val += mat[k * n + i + 2] * other[j * q + k + 2];
                res[j * n + i + 2] = val;
            }
        return res;
    }
}

