export function approxEquals(x: number, y: number, epsilon: number = 0.000001): boolean {
    if (x === y)
        return true;
    let absX: number = Math.abs(x);
    let absY: number = Math.abs(y);
    let diff: number = Math.abs(x - y);
    if (x * y == 0)
        return diff < (epsilon * epsilon);
    else
        return diff / (absX + absY) < epsilon;
}

